   136→    setError('');
   137→
   138→    if (!currentUser) {
   139→      setError('Please sign in to use this tool.');
   140→      return;
   141→    }
   142→
   143→    if (!canUseTool(categoryId)) {
   144→      if (isAtLimit()) {
   145→        setError(t('ui.dailyLimitText', { limit: 3, defaultValue: "Daily usage limit reached. Upgrade to Pro for unlimited access." }));
   146→      } else {
   147→        setError(t('ui.proOnlyText', { defaultValue: 'This category is available on Pro and Business plans.' }));
   148→      }
   149→      return;
   150→    }
   151→
   152→    const validationError = validateInputs();
   153→    if (validationError) {
   154→      setError(validationError);
   155→      return;
   156→    }
   157→
   158→    setOutput('');
   159→    finalOutputRef.current = '';
   160→    setIsStreaming(true);
   161→    abortRef.current = false;
   162→    const capturedInputs = { ...inputs };
