   258→          </div>
   259→          <Link to="/pricing" className="btn btn-primary btn-sm">{t('ui.upgradeNow', { defaultValue: 'Upgrade Now' })}</Link>
   260→        </div>
   261→      )}
   262→
   263→      <div className="ai-tool__layout">
   264→        {/* Input Panel */}
   265→        <div className="ai-tool__panel ai-tool__input-panel">
