   282→            )}
   283→
   284→            <div className="ai-tool__actions">
   285→              {isStreaming ? (
   286→                <button type="button" className="btn btn-danger" onClick={handleStop}>
   287→                  ⏹ {t('ui.stopGenerating', { defaultValue: 'Stop Generating' })}
