   292→                  className="btn btn-primary"
   293→                  disabled={locked || atLimit}
   294→                >
   295→                  <span>✨</span>
   296→                  {t('ui.generateWithAI', { defaultValue: 'Generate with AI' })}
   297→                </button>
   298→              )}
   299→              {output && !isStreaming && (
   300→                <button type="button" className="btn btn-ghost btn-sm" onClick={handleClear}>
   301→                  {t('ui.clear', { defaultValue: 'Clear' })}
