   359→                  {isStreaming && <span className="ai-tool__cursor">▋</span>}
   360→                </motion.div>
   361→              )}
   362→            </AnimatePresence>
   363→          </div>
   364→        </div>
   365→      </div>
   366→
   367→      {/* Query History */}
   368→      {history.length > 0 && (
   369→        <div className="ai-tool__history">
   370→          <button
   371→            type="button"
   372→            className="ai-tool__history-toggle"
   373→            onClick={() => setHistoryOpen((o) => !o)}
   374→          >
   375→            <span>🕐</span>
   376→            <span>{t('ui.history', { defaultValue: 'Recent queries' })} ({history.length})</span>
   377→            <span className={`ai-tool__history-arrow ${historyOpen ? 'open' : ''}`}>▾</span>
   378→          </button>
   379→
   380→          {historyOpen && (
   381→            <div className="ai-tool__history-list">
   382→              {history.map((entry) => {
   383→                const firstKey = Object.keys(entry.inputs).find((k) => !k.startsWith('_'));
   384→                const raw = firstKey ? String(entry.inputs[firstKey] || '') : '';
   385→                const preview = raw.slice(0, 70);
   386→                const d = new Date(entry.timestamp);
   387→                const timeStr =
   388→                  d.toLocaleDateString([], { month: 'short', day: 'numeric' }) +
   389→                  ' · ' +
   390→                  d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
   391→                return (
   392→                  <button
   393→                    key={entry.id}
   394→                    type="button"
   395→                    className="ai-tool__history-item"
   396→                    onClick={() => {
   397→                      setInputs(entry.inputs);
   398→                      setOutput(entry.output);
   399→                      finalOutputRef.current = entry.output;
   400→                      setHistoryOpen(false);
   401→                    }}
   402→                  >
   403→                    <span className="ai-tool__history-time">{timeStr}</span>
   404→                    <span className="ai-tool__history-preview">{preview}{raw.length > 70 ? '…' : ''}</span>
   405→                  </button>
   406→                );
   407→              })}
   408→            </div>
   409→          )}
   410→        </div>
