    14→// Stream AI response using fetch + ReadableStream
    15→export async function streamAIResponse({ categoryId, toolId, inputs, onChunk, onDone, onError }) {
    16→  try {
    17→    const authHeaders = await getAuthHeader();
    18→    const response = await fetch(`${API_URL}/api/ai/generate`, {
    19→      method: 'POST',
    20→      headers: {
    21→        'Content-Type': 'application/json',
    22→        ...authHeaders,
    23→      },
    24→      body: JSON.stringify({ categoryId, toolId, inputs }),
    25→    });
    26→
    27→    if (!response.ok) {
    28→      const err = await response.json().catch(() => ({ error: 'Request failed' }));
    29→      throw new Error(err.error || `HTTP ${response.status}`);
    30→    }
    31→
    32→    const reader = response.body.getReader();
    33→    const decoder = new TextDecoder();
    34→
    35→    while (true) {
    36→      const { done, value } = await reader.read();
    37→      if (done) break;
    38→
    39→      const chunk = decoder.decode(value, { stream: true });
    40→      const lines = chunk.split('\n');
    41→
    42→      for (const line of lines) {
    43→        if (line.startsWith('data: ')) {
    44→          const data = line.slice(6).trim();
    45→          if (data === '[DONE]') {
    46→            onDone?.();
    47→            return;
    48→          }
    49→          try {
    50→            const parsed = JSON.parse(data);
    51→            if (parsed.text) onChunk(parsed.text);
    52→            if (parsed.error) throw new Error(parsed.error);
    53→          } catch (e) {
    54→            if (e.message !== 'Unexpected end of JSON input') {
    55→              // silently skip malformed chunks
    56→            }
    57→          }
    58→        }
    59→      }
    60→    }
    61→    onDone?.();
    62→  } catch (err) {
    63→    onError?.(err.message || 'Failed to generate response');
    64→  }
    65→}
